const response = $input.first().json;
const webhooks = response.data || response.webhooks || response || [];

if (!Array.isArray(webhooks)) return [];

// Return each webhook ID so we can fetch its logs
return webhooks.map(w => ({
  json: {
    webhookId: w.id,
    webhookUrl: w.url,
    events: w.events
  }
}));

const response = $input.first().json;
const logs = response.data || response.logs || response || [];

if (!Array.isArray(logs) || logs.length === 0) return [];

const retryable = logs.filter(l => l.status === 'failed');
if (retryable.length === 0) return [];

// Output: alert message + list of log IDs to retry
const lines = retryable.slice(0, 5).map(l =>
  `• ${l.event_type || l.event || 'unknown'} @ ${l.created_at || ''} (${l.http_status || 'timeout'})`
).join('\n');

return [{
  json: {
    webhookId: $('Extract Webhook IDs').item.json.webhookId,
    webhookUrl: $('Extract Webhook IDs').item.json.webhookUrl,
    failedCount: retryable.length,
    logIds: retryable.map(l => l.id),
    alertMessage: `🔴 *${retryable.length} failed webhook(s)*\nEndpoint: ${$('Extract Webhook IDs').item.json.webhookUrl}\n\n${lines}`
  }
}];

const logIds = $input.first().json.logIds || [];
const webhookId = $input.first().json.webhookId;

// Return each log ID as separate item for retry
return logIds.slice(0, 5).map(id => ({
  json: { webhookId, logId: id }
}));
